sql:
SELECT DISTINCT store_id
FROM sales
ORDER BY store_id ASC;

SELECT AVG(total_sales_quantity) AS average_sales_quantity
FROM (
    SELECT store_id, SUM(sales_quantity) AS total_sales_quantity
    FROM sales
    GROUP BY store_id
) AS SalesPerStore;

SELECT DISTINCT year, store_id, article_code, sales_quantity, store_sales_quantity, sale_date, product_name, product_category, product_supplier, sale_amount
FROM sales
WHERE year = 2022;

external_knowledge:
- "blossomed in our garden of sales" refers to products that have been sold;
- "sum of their blossoms" refers to the total quantity of each product sold;
- "total yield of the store garden" refers to the total sales quantity at the store level for each product;
- "blooming season of 2022" refers to the period from January 1, 2022, to December 31, 2022.

sql:
SELECT stores.store_name, sales.sale_amount
FROM stores
LEFT JOIN sales ON stores.store_id = sales.store_id;
